117	    fail_fast: bool,
118	    root_temp: &Path,
119	) -> Result<rbtdre_RunResult, String> {
120	    let mut passed = 0usize;
121	    let mut failed = 0usize;
122	    let mut skipped = 0usize;
123	
124	    'outer: for section in sections {
125	        eprintln!(
126	            "\n{}--- {} ---{}",
127	            colors.white, section.name, colors.reset
128	        );
