132	            std::fs::create_dir_all(&case_dir).map_err(|e| {
133	                format!("rbtd: failed to create case dir '{}': {}", case.name, e)
134	            })?;
135	
136	            let verdict = (case.func)(&case_dir);
137	            rbtdre_write_trace(&case_dir, case.name, &verdict);
138	
139	            match &verdict {
140	                rbtdre_Verdict::Pass => {
141	                    eprintln!("{}PASSED:{} {}", colors.green, colors.reset, case.name);
142	                    passed += 1;
143	                }
144	                rbtdre_Verdict::Fail(_) => {
145	                    eprintln!("{}FAILED:{} {}", colors.red, colors.reset, case.name);
146	                    failed += 1;
147	                    if fail_fast {
148	                        break 'outer;
149	                    }
150	                }
151	                rbtdre_Verdict::Skip(_) => {
152	                    eprintln!(
153	                        "{}SKIPPED:{} {}",
154	                        colors.yellow, colors.reset, case.name
155	                    );
156	                    skipped += 1;
157	                }
158	            }
159	        }
160	    }
