172	    let total = result.passed + result.failed + result.skipped;
173	    let (color, end_color) = if result.failed > 0 {
174	        (colors.red, colors.reset)
175	    } else {
176	        (colors.green, colors.reset)
177	    };
178	
179	    eprintln!(
180	        "\n{}{} passed, {} failed, {} skipped ({} total){}",
181	        color, result.passed, result.failed, result.skipped, total, end_color,
182	    );
183	    eprintln!("Trace dir: {}", result.temp_dir.display());
184	}
