16	//
17	// RBTDRC — crucible test cases for theurge end-to-end testing
18	//
19	// Cases execute inside a charged crucible (sentry + pentacle + bottle).
20	// Thread-local context bridges the static case function signature with
21	// the mutable invocation context needed for tabtarget calls.
22	
23	use std::cell::RefCell;
24	use std::io::Write;
25	use std::path::Path;
26	use std::process::{Command, Stdio};
27	
28	use crate::case;
29	use crate::rbtdre_engine::{rbtdre_Section, rbtdre_Verdict};
30	use crate::rbtdri_invocation::{
31	    rbtdri_Context, rbtdri_invoke, rbtdri_invoke_global, rbtdri_invoke_imprint,
32	    rbtdri_parse_ifrit_verdict, rbtdri_read_burv_fact,
33	};
34	use crate::rbtdrm_manifest::{
35	    RBTDRM_COLOPHON_ABJURE, RBTDRM_COLOPHON_ACCESS_PROBE, RBTDRM_COLOPHON_BARK,
36	    RBTDRM_COLOPHON_FIAT, RBTDRM_COLOPHON_JETTISON_HALLMARK_IMAGE, RBTDRM_COLOPHON_KLUDGE,
37	    RBTDRM_COLOPHON_ORDAIN, RBTDRM_COLOPHON_PLUMB_COMPACT, RBTDRM_COLOPHON_PLUMB_FULL,
38	    RBTDRM_COLOPHON_REKON_HALLMARK, RBTDRM_COLOPHON_SUMMON, RBTDRM_COLOPHON_TALLY,
39	    RBTDRM_COLOPHON_VOUCH, RBTDRM_COLOPHON_WREST_HALLMARK_IMAGE, RBTDRM_COLOPHON_WRIT,
40	};
41	
42	// ── Thread-local invocation context ──────────────────────────
43	
44	/// Ifrit binary name inside the bottle container.
45	const RBTDRC_IFRIT_BINARY: &str = "rbid";
46	
47	/// Test connectivity target — ICANN-owned, stable single /20 CIDR (192.0.32.0/20)
48	const RBTDRC_CONNECTIVITY_DOMAIN: &str = "www.internic.net";
49	
50	thread_local! {
51	    static RBTDRC_CTX: RefCell<Option<rbtdri_Context>> = RefCell::new(None);
52	}
53	
54	/// Store invocation context for case functions. Called before run_sections.
55	pub fn rbtdrc_set_context(ctx: rbtdri_Context) {
56	    RBTDRC_CTX.with(|c| *c.borrow_mut() = Some(ctx));
57	}
58	
59	/// Retrieve invocation context after cases complete. Called for quench.
60	pub fn rbtdrc_take_context() -> rbtdri_Context {
61	    RBTDRC_CTX.with(|c| {
62	        c.borrow_mut()
63	            .take()
64	            .expect("rbtdrc: no context — was rbtdrc_set_context called?")
65	    })
66	}
67	
68	fn rbtdrc_with_ctx<F>(f: F) -> rbtdre_Verdict
69	where
70	    F: FnOnce(&mut rbtdri_Context) -> rbtdre_Verdict,
71	{
72	    RBTDRC_CTX.with(|c| {
73	        let mut opt = c.borrow_mut();
74	        let ctx = opt
75	            .as_mut()
76	            .expect("rbtdrc: no invocation context for case execution");
77	        f(ctx)
78	    })
79	}
80	
81	// ── Helpers ──────────────────────────────────────────────────
82	
83	/// Invoke ifrit inside the bottle via bark, saving stdout/stderr to case dir.
84	fn rbtdrc_invoke_ifrit(
85	    ctx: &mut rbtdri_Context,
86	    attack: &str,
87	    dir: &Path,
88	) -> rbtdre_Verdict {
89	    let result = match rbtdri_invoke(ctx, RBTDRM_COLOPHON_BARK, &[RBTDRC_IFRIT_BINARY, attack]) {
90	        Ok(r) => r,
91	        Err(e) => return rbtdre_Verdict::Fail(format!("bark invocation error: {}", e)),
92	    };
93	    let _ = std::fs::write(dir.join("bark-stdout.txt"), &result.stdout);
94	    let _ = std::fs::write(dir.join("bark-stderr.txt"), &result.stderr);
95	    rbtdri_parse_ifrit_verdict(&result.stdout, result.exit_code)
96	}
97	
98	/// Invoke ifrit inside the bottle via bark with extra arguments.
99	fn rbtdrc_invoke_ifrit_with_args(
100	    ctx: &mut rbtdri_Context,
101	    attack: &str,
102	    extra_args: &[&str],
103	    dir: &Path,
104	) -> rbtdre_Verdict {
