31	
32	/// Sub-assertion within a case: run bash snippet, check exit code.
33	struct RbtdrfSub {
34	    label: &'static str,
35	    setup: &'static str,
36	    command: &'static str,
37	    expect_ok: bool,
38	}
39	
40	impl RbtdrfSub {
41	    const fn ok(label: &'static str, setup: &'static str) -> Self {
42	        Self { label, setup, command: "buv_vet \"TEST\"", expect_ok: true }
43	    }
44	    const fn fatal(label: &'static str, setup: &'static str) -> Self {
45	        Self { label, setup, command: "buv_vet \"TEST\"", expect_ok: false }
46	    }
47	    const fn ok_cmd(label: &'static str, setup: &'static str, command: &'static str) -> Self {
48	        Self { label, setup, command, expect_ok: true }
49	    }
50	    const fn fatal_cmd(label: &'static str, setup: &'static str, command: &'static str) -> Self {
51	        Self { label, setup, command, expect_ok: false }
52	    }
53	}
54	
55	/// Run a bash script, return (exit_code, stdout, stderr). Saves traces to case dir.
56	fn rbtdrf_run_bash(
57	    project_root: &Path,
58	    script: &str,
59	    dir: &Path,
60	    trace_prefix: &str,
61	) -> Result<(i32, String, String), String> {
62	    let output = Command::new("bash")
63	        .arg("-c")
64	        .arg(script)
65	        .current_dir(project_root)
66	        .output()
67	        .map_err(|e| format!("bash execution failed: {}", e))?;
